async (page) => {
  // Player centered at ~(640, 360). Rat is 1 tile away - try clicking slightly above/below
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Try clicking just below player (1 tile down at ~48px per tile)
  await click(640, 410);
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    if (!s) return 'no state';
    return JSON.stringify({
      pos: s.player_position,
      hp: s.player_stats ? s.player_stats.hp : null,
      target: s.current_target,
      nearest: s.nearest_mob,
      top3: s.nearby_entities ? s.nearby_entities.slice(0, 3).map(e => ({name:e.name, dist:e.distance, hp:e.hp, cx:e.click_x, cy:e.click_y, on:e.on_screen})) : []
    });
  });
  return state;
}

